import React from "react";
import { useNavigate } from "react-router-dom";
import {
  BarChart2,
  BarChart3,
  Brain,
  Compass,
  Folder,
  GitFork,
  Home,
  LayoutGrid,
  ListChecks,
  LogOut,
  Settings as SettingsIcon,
  Squircle,
} from "lucide-react";
import { Avatar } from "../ui";
import { logout } from "../../api";
import { useUser } from "../../contexts/UserContext";
import { SidebarNavItem } from "./SidebarNavItem";
import SidebarMiniGraph from "../Sidebar/SidebarMiniGraph";
import styles from "./Sidebar.module.css";

const ROLE_LABELS = {
  admin: "Admin",
  project_manager: "Project Manager",
  architect: "Architect",
};

// Base nav items — shown to all roles
const BASE_NAV_ITEMS = [
  { to: "/my-world",      icon: Compass,    label: "My World" },
  { to: "/",              icon: Home,       label: "Dashboard", end: true },
  { to: "/portfolio",     icon: LayoutGrid, label: "Portfolio" },
  { to: "/tasks",         icon: ListChecks, label: "Tasks" },
  { to: "/gantt",         icon: BarChart3,  label: "Gantt" },
  { to: "/files",         icon: Folder,     label: "Files" },
  { to: "/knowledge",     icon: GitFork,    label: "Project Graph" },
  { to: "/knowledge-web", icon: Brain,      label: "Knowledge Web" },
];

// Management — admin + project_manager only
const MANAGER_NAV_ITEMS = [
  { to: "/management", icon: BarChart2, label: "Management" },
];

const SETTINGS_NAV_ITEMS = [
  { to: "/settings", icon: SettingsIcon, label: "Settings" },
];

export function Sidebar() {
  const navigate = useNavigate();
  const { user, role, loading, stopHeartbeat, isAdmin, isProjectManager } = useUser();
  const navItems = [
    ...BASE_NAV_ITEMS,
    ...(isAdmin || isProjectManager ? MANAGER_NAV_ITEMS : []),
    ...SETTINGS_NAV_ITEMS,
  ];

  const handleLogout = async () => {
    stopHeartbeat();
    try {
      await logout();
    } finally {
      navigate("/login", { replace: true });
    }
  };

  return (
    <aside className={styles.sidebar} aria-label="Primary">
      <div className={styles.brand}>
        <span className={styles.brandMark} aria-hidden="true">
          <Squircle size={18} strokeWidth={2.5} />
        </span>
        <span className={styles.brandWord}>Vitruvius</span>
      </div>

      <nav className={styles.nav}>
        {navItems.map((item) => (
          <SidebarNavItem key={item.to} {...item} />
        ))}
      </nav>

      <div className={styles.miniGraphSection}>
        <SidebarMiniGraph />
        <div className={styles.miniGraphDivider} />
      </div>

      <div className={styles.footer}>
        <div className={styles.userCard}>
          <Avatar
            name={user?.name}
            email={user?.email}
            size="md"
          />
          <div className={styles.userMeta}>
            <span className={styles.userName}>
              {loading ? "…" : user?.name ?? "Signed in"}
            </span>
            {user?.email && (
              <span className={styles.userEmail}>{user.email}</span>
            )}
            {role && (
              <span className={styles.roleBadge}>
                {ROLE_LABELS[role] ?? role}
              </span>
            )}
          </div>
          <button
            type="button"
            onClick={handleLogout}
            title="Log out"
            className={styles.logoutBtn}
            aria-label="Log out"
          >
            <LogOut size={16} strokeWidth={2} />
          </button>
        </div>
      </div>
    </aside>
  );
}

export default Sidebar;
